488f33d9-66b1-4c1c-852f-9f54082b0a1c	9ec00422-76de-4f03-92e7-ecf706310094	\N	32	{"ss31": {"dosage": "5-10mg daily", "protocol": "Subcutaneous targeting mitochondria", "rationale": "SS-31 targets inner mitochondrial membrane. Consider for advanced optimization or if energy markers decline.", "recommended": false}, "motsc": {"dosage": "5-10mg weekly", "protocol": "Subcutaneous 1-2x weekly", "rationale": "MOTS-c is a mitochondrial-derived peptide that enhances metabolic function and exercise capacity. Particularly beneficial for maintaining insulin sensitivity and energy production.", "recommended": true}, "tb500": {"dosage": "2-2.5mg twice weekly", "protocol": "4-6 week loading, then maintenance", "rationale": "TB-500 promotes tissue repair and reduces inflammation. Synergizes well with BPC-157 for comprehensive healing support.", "recommended": true}, "bpc157": {"dosage": "250-500mcg daily", "protocol": "4-6 week cycles with 2 week breaks", "rationale": "BPC-157 supports tissue repair and gut health. Based on good baseline inflammation markers, this peptide is well-tolerated and can accelerate recovery from training.", "recommended": true}, "status": "good", "cjc1295": {"dosage": "100-200mcg 2-3x weekly", "protocol": "Often paired with Ipamorelin for synergistic GH release", "rationale": "Growth hormone optimization not currently a priority based on markers.", "recommended": false}, "nadPlus": {"dosage": "250-500mg NMN or NR daily", "protocol": "Oral NAD+ precursors daily, or periodic IV NAD+ infusions", "rationale": "NAD+ levels naturally decline with age, affecting cellular energy production, DNA repair, and metabolic function. Supplementation supports mitochondrial health and cognitive function.", "recommended": true}, "ghStatus": "Growth hormone axis functioning normally based on available markers. IGF-1 levels optimal for age.", "epithalon": {"dosage": "5-10mg daily for 10-20 days", "protocol": "Cyclical use 2-3 times per year", "rationale": "Epithalon activates telomerase, potentially supporting longevity. Recommended for periodic use as part of comprehensive anti-aging strategy.", "recommended": true}, "ipamorelin": {"dosage": "200-300mcg before bed", "protocol": "Daily subcutaneous, often combined with CJC-1295", "rationale": "Not currently indicated. May consider for body composition optimization in future.", "recommended": false}, "sermorelin": {"dosage": "200-300mcg before bed", "protocol": "Daily subcutaneous, 5 days on 2 off", "rationale": "Growth hormone axis appears functional based on current markers. Consider if sleep quality or recovery become concerns.", "recommended": false}, "overallNotes": "Peptide strategy: Start with BPC-157 and TB-500 for recovery support, add NAD+ precursors for cellular health, and consider periodic Epithalon cycles for longevity. MOTS-c can enhance metabolic function. GH secretagogues not currently indicated but may be considered in future.", "thymosinAlpha1": {"dosage": "1.6mg 2-3x weekly", "protocol": "Subcutaneous for immune modulation", "rationale": "Immune function appears adequate. Consider during illness or if inflammation markers elevate.", "recommended": false}}	{"shbg": 32, "freeT": 18.5, "estradiol": 28, "testosterone": 612, "detailedAnalysis": "Your hormone profile is healthy. Testosterone at 612 ng/dL places you in the optimal range. Free testosterone at 18.5 pg/mL indicates good bioavailability. SHBG at 32 nmol/L is balanced - not too high to bind excess testosterone, not too low. Estradiol at 28 pg/mL is appropriate for your testosterone level. Continue current lifestyle practices to maintain these levels. If you notice declining energy, libido, or recovery, retest in 6 months.", "trtRecommendation": {"frequency": "N/A", "maxDosage": "Not currently recommended", "rationale": "Current testosterone levels (612 ng/dL) and free T (18.5 pg/mL) are within optimal range. TRT is not indicated at this time. Focus on natural optimization through lifestyle factors.", "monitoring": ["Retest total and free T in 6-12 months", "Monitor symptoms of low T", "Track energy and libido"], "recommended": false, "naturalAlternatives": ["Quality sleep (7-9 hours)", "Resistance training 3-4x weekly", "Stress management", "Maintain healthy body fat (10-20%)", "Zinc and Vitamin D optimization", "Limit alcohol consumption"]}, "testosteroneStatus": "good"}	{"hba1c": 5.2, "notes": "Excellent metabolic health. Fasting glucose of 92 mg/dL is optimal (under 100). HbA1c of 5.2% indicates excellent long-term glucose control. Insulin at 6.8 uIU/mL shows no hyperinsulinemia. HOMA-IR of 1.5 indicates good insulin sensitivity. Maintain through regular exercise, balanced nutrition with adequate protein, and avoiding processed carbohydrates.", "homaIr": 1.5, "glucose": 92, "insulin": 6.8}	{"crp": 0.8, "notes": "Inflammation markers are well-controlled. CRP at 0.8 mg/L (optimal <1.0) indicates low systemic inflammation. Homocysteine at 8.2 umol/L is healthy (optimal <10). Ferritin at 95 ng/mL is balanced - enough iron stores without excess oxidative potential. Continue anti-inflammatory practices: omega-3 fatty acids, colorful vegetables, quality sleep, stress management.", "status": "good", "ferritin": 95, "homocysteine": 8.2}	[{"time": "6:00 AM", "action": "Wake + Morning Light", "details": "Get 10-15 minutes of direct sunlight exposure within the first hour of waking. This sets your circadian rhythm, triggers cortisol awakening response, and programs better melatonin release 14-16 hours later. Even on cloudy days, outdoor light is 10-50x brighter than indoor lighting.", "priority": "high"}, {"time": "6:15 AM", "action": "Hydration Protocol", "details": "Drink 16-20oz water with a pinch of sea salt (sodium) or electrolyte mix. After 7-8 hours without water, you wake dehydrated. Proper hydration improves cognitive function, energy, and nutrient transport. Add lemon if desired for digestion support.", "priority": "high"}, {"time": "6:25 AM", "action": "Cold Exposure", "details": "End your shower with 1-3 minutes of cold water (as cold as tolerable). This increases norepinephrine by 200-300%, improving mood and alertness for hours. Cold exposure also activates brown fat, improves recovery, and builds mental resilience. Start with 30 seconds and gradually increase.", "priority": "medium"}, {"time": "6:35 AM", "action": "Movement/Mobility", "details": "10-15 minute mobility routine focusing on hips, thoracic spine, and shoulders. This activates the nervous system, improves joint health, and prepares your body for the day. Include cat-cow stretches, hip circles, and shoulder rotations.", "priority": "medium"}, {"time": "6:50 AM", "action": "Breathwork", "details": "5-10 minutes of box breathing (4 seconds inhale, 4 hold, 4 exhale, 4 hold) or similar practice. This activates parasympathetic nervous system, reduces cortisol, and improves focus. Sets calm, intentional tone for the day.", "priority": "medium"}]	[{"time": "7:00 PM", "action": "Dim Lights & Block Blue Light", "details": "Switch to warm lighting and wear blue light blocking glasses. Blue light after sunset suppresses melatonin production by up to 50%. This single habit can dramatically improve sleep quality. Use red/amber lights in bedroom.", "priority": "high"}, {"time": "8:00 PM", "action": "Digital Sunset", "details": "Stop work emails and stimulating content. Transition to relaxing activities: reading (paper book preferred), gentle stretching, conversation, or meditation. Cortisol should naturally decline in evening - don't spike it with stressful content.", "priority": "high"}, {"time": "8:30 PM", "action": "Evening Supplements", "details": "Take magnesium glycinate 300-400mg. Magnesium supports GABA activity for calm, aids muscle relaxation, and improves sleep architecture. Best taken 1-2 hours before bed. Add zinc 15-30mg if levels are suboptimal.", "priority": "high"}, {"time": "9:00 PM", "action": "Cool Down Environment", "details": "Set bedroom temperature to 65-68°F (18-20°C). Your core body temperature must drop 2-3 degrees for sleep onset and to stay asleep. This is physiologically non-negotiable. Consider a cooling mattress pad if overheating is an issue.", "priority": "high"}, {"time": "9:30-10:00 PM", "action": "Sleep", "details": "Aim for consistent bedtime within a 30-minute window, even on weekends. Adults need 7-9 hours. Sleep is when growth hormone peaks (especially first 90 min), memories consolidate, the glymphatic system clears brain toxins, and tissue repairs occur. It's not optional for optimization.", "priority": "high"}]	[{"name": "Vitamin D3", "notes": "Target blood level of 40-60 ng/mL. Most people do well with 1000-2000 IU. Only increase if blood levels remain low despite supplementation.", "dosage": "1000-2000 IU daily (NOT 5000 IU unless severely deficient)", "timing": "Morning with fat-containing meal", "purpose": "Optimize vitamin D for immune function, bone health, and hormone production", "mechanism": "Fat-soluble hormone precursor that regulates 200+ genes including immune modulation, calcium homeostasis, and testosterone synthesis. Vitamin D receptors exist in nearly every tissue.", "synergies": ["Vitamin K2", "Magnesium", "Omega-3"], "precautions": "Retest levels after 3 months. 5000 IU is excessive for most people and can lead to hypercalcemia long-term. Take with K2 to direct calcium to bones, not arteries.", "evidenceLevel": "strong", "expectedBenefits": "Improved immune function, better mood, optimized hormone levels, reduced inflammation, stronger bones"}, {"name": "Omega-3 (EPA/DHA)", "notes": "Aim for higher EPA for inflammation, higher DHA for brain. Many people are deficient due to low fish intake.", "dosage": "2-3g combined EPA/DHA daily", "timing": "With meals containing fat for absorption", "purpose": "Reduce inflammation, support brain health, cardiovascular protection", "mechanism": "EPA and DHA are incorporated into cell membranes, improving fluidity. They compete with omega-6 for enzymatic conversion, reducing pro-inflammatory eicosanoids. Critical for brain structure and function.", "synergies": ["Vitamin D", "Curcumin", "Astaxanthin"], "precautions": "Choose quality fish oil or algae-based (for vegans) to avoid heavy metals. May thin blood slightly - mention to doctor before surgery.", "evidenceLevel": "strong", "expectedBenefits": "Reduced inflammation (lower CRP), improved mood, better cognitive function, cardiovascular protection, reduced joint pain"}, {"name": "Magnesium Glycinate", "notes": "Most people are deficient due to depleted soils and low intake. Critical mineral for optimization.", "dosage": "300-400mg elemental magnesium before bed", "timing": "1-2 hours before sleep", "purpose": "Sleep quality, muscle relaxation, stress reduction, 300+ enzymatic reactions", "mechanism": "Magnesium is cofactor in 300+ enzymatic reactions. Glycinate form crosses blood-brain barrier, supports GABA activity (calming neurotransmitter), relaxes muscles, and improves sleep architecture.", "synergies": ["Vitamin D", "B6", "Zinc"], "precautions": "Glycinate is well-tolerated. Oxide form is poorly absorbed and causes GI issues. Threonate is good for cognitive focus.", "evidenceLevel": "strong", "expectedBenefits": "Better sleep quality, reduced muscle tension, improved stress response, better exercise recovery, regular bowel movements"}, {"name": "Creatine Monohydrate", "notes": "One of the most studied and effective supplements. Benefits both athletes and non-athletes for brain health.", "dosage": "5g daily", "timing": "Anytime - with food or post-workout", "purpose": "Strength, power, cognitive function, cellular energy", "mechanism": "Creatine is stored as phosphocreatine in muscles and brain, rapidly regenerating ATP during high-intensity activity. Also has cognitive benefits through brain energy metabolism.", "synergies": ["Beta-Alanine", "HMB", "Protein"], "precautions": "Stay well hydrated. No loading phase necessary - 5g daily reaches saturation in 3-4 weeks. Monohydrate is the most studied form.", "evidenceLevel": "strong", "expectedBenefits": "Increased strength and power output, faster recovery between sets, improved cognitive performance, potential neuroprotective effects"}]	[{"day": "Monday", "type": "Upper Body Push", "duration": "45-50 min", "exercises": ["Bench Press 4x6-8 RPE 7-8", "Overhead Press 3x8-10", "Dips 3x10-12", "Lateral Raises 4x12-15", "Tricep Pushdowns 3x12-15"], "intensity": "High"}, {"day": "Tuesday", "type": "Lower Body", "duration": "50 min", "exercises": ["Squats 4x6-8 RPE 7-8", "Romanian Deadlifts 4x8-10", "Bulgarian Split Squats 3x10 each", "Leg Curls 3x12", "Calf Raises 4x15"], "intensity": "High"}, {"day": "Wednesday", "type": "Active Recovery", "duration": "45-60 min", "exercises": ["30-min Zone 2 walk or light cardio", "15-min full body mobility routine", "10-min foam rolling"], "intensity": "Low - conversational pace"}, {"day": "Thursday", "type": "Upper Body Pull", "duration": "45 min", "exercises": ["Pull-ups or Lat Pulldowns 4x6-10", "Barbell or Dumbbell Rows 4x8-10", "Face Pulls 3x15-20", "Bicep Curls 3x12", "Rear Delt Flies 3x15"], "intensity": "High"}, {"day": "Friday", "type": "Lower Body + Deadlift Focus", "duration": "50 min", "exercises": ["Deadlifts 4x5 RPE 7-8", "Leg Press 3x10-12", "Walking Lunges 3x10 each", "Leg Extensions 3x12", "Core Work 10 min"], "intensity": "High"}, {"day": "Saturday", "type": "Zone 2 Cardio + Flexibility", "duration": "60-75 min", "exercises": ["45-60 min steady cardio at conversational pace (cycling, jogging, rowing)", "15-20 min stretching or yoga"], "intensity": "Low - Heart rate 60-70% max"}, {"day": "Sunday", "type": "Complete Rest or Light Activity", "duration": "Optional", "exercises": ["Optional: gentle walk, yoga, family activities", "Focus on recovery, meal prep, and sleep"], "intensity": "Very Low"}]	[{"level": "low", "category": "Vitamin D Optimization", "description": "Ensure vitamin D levels are regularly monitored", "recommendation": "Supplement with 1000-2000 IU daily (not 5000 IU which is excessive). Retest in 3 months. Target blood level 40-60 ng/mL."}, {"level": "low", "category": "Sleep Consistency", "description": "Sleep is foundational for all optimization efforts", "recommendation": "Prioritize 7-8 hours nightly with consistent sleep/wake times. Implement evening routine to improve sleep quality."}, {"level": "low", "category": "Stress Management", "description": "Chronic stress undermines all other optimization efforts", "recommendation": "Implement daily stress management practice: breathwork, meditation, or nature exposure. Minimum 10 minutes daily."}]	Your biomarkers indicate a solid foundation for health optimization. Key priorities: 1) Maintain excellent sleep hygiene - this is your highest-leverage habit. 2) Continue or begin resistance training 3-4x weekly for hormone optimization and longevity. 3) Consider BPC-157, NAD+ precursors, and periodic Epithalon for enhanced recovery and longevity support. Your testosterone and metabolic markers are healthy - focus on maintaining these through lifestyle. If any symptoms of low energy or poor recovery develop, retest hormones in 6 months. The detailed peptide and supplement recommendations above are personalized to your current markers. This is a marathon, not a sprint - focus on sustainable habits that you can maintain long-term.	beginner	2025-12-15 15:45:57.835727	\N	{"coldExposure": {"benefits": "Increases norepinephrine 200-300% (mood and focus boost lasting hours), activates brown fat for metabolic health, reduces inflammation, improves immune function, builds mental resilience", "protocol": "Start with 30-second cold shower endings. Build to 2-3 minutes over weeks. Or cold plunge at 50-59°F for 2-11 minutes total per week. Never do immediately after strength training (blunts adaptation).", "rationale": "Deliberate cold exposure has robust evidence for mood, metabolism, and recovery. The stress is hormetic - brief controlled stress that makes you more resilient. Start gradually and listen to your body. The mental challenge is part of the benefit.", "recommended": true}, "movementGuidance": {"rationale": "Non-exercise activity thermogenesis (NEAT) matters more than many realize. Walking improves insulin sensitivity, reduces inflammation, supports mental health, and aids digestion. It's low-stress movement that everyone can do daily. Mobility prevents injury and maintains functional movement patterns.", "mobilityWork": "10-15 minutes daily focusing on hips, thoracic spine, and shoulders. These are common problem areas that affect posture and performance.", "standingBreaks": "Stand and move every 45-60 minutes if you have a sedentary job. Prolonged sitting is independently harmful regardless of exercise.", "dailyStepTarget": "8,000-10,000 steps minimum (more is better up to ~12,000)"}, "socialConnection": {"rationale": "Humans are social animals. Positive social connections reduce stress hormones, lower blood pressure, improve immune function, and promote healthy behaviors. No amount of supplements or biohacking can replace genuine human connection.", "importance": "Strong social connections are as predictive of longevity as smoking cessation. Loneliness increases mortality risk equivalent to smoking 15 cigarettes daily.", "suggestions": ["Schedule regular time with friends and family", "Join community groups, sports leagues, or hobby clubs", "Prioritize face-to-face interaction over digital", "Express gratitude regularly", "Be vulnerable and authentic in relationships"]}, "stressManagement": {"rationale": "Chronic stress chronically elevates cortisol, which impairs testosterone production, increases abdominal fat storage, raises inflammation, disrupts sleep, and accelerates aging. Your biomarkers will never fully optimize without addressing stress. The goal isn't eliminating stress but developing resilience and recovery practices.", "techniques": ["Box breathing (4-4-4-4 pattern)", "5-10 minute morning meditation", "Regular nature exposure", "Physical exercise as stress release", "Journaling for mental clarity", "Social connection with supportive people"], "dailyPractice": "Minimum 10 minutes of intentional stress-reduction practice daily. Non-negotiable."}, "sunlightExposure": {"benefits": "Sets circadian rhythm, triggers healthy cortisol rise, improves nighttime melatonin production, supports vitamin D synthesis, improves mood", "rationale": "Morning light is the most powerful signal for your biological clock. It anchors your circadian rhythm and determines sleep quality 14-16 hours later. Indoor lighting is 10-50x dimmer than outdoor light, even on cloudy days. This is free and one of the highest-impact habits you can develop.", "morningTarget": "10-30 minutes of outdoor light within first 60 minutes of waking (more on cloudy days)"}, "sleepOptimization": {"rationale": "Sleep is the single most important factor for health optimization. Growth hormone peaks during deep sleep (especially first 90 minutes). Memory consolidation, cellular repair, metabolic regulation, and brain toxin clearance all depend on quality sleep. No supplement, diet, or training program can compensate for poor sleep.", "qualityTips": ["Keep room at 65-68°F (18-20°C)", "Complete darkness or quality sleep mask", "No screens 1 hour before bed", "Consistent sleep/wake times even weekends", "No caffeine after 2 PM (earlier if sensitive)", "Finish eating 3+ hours before bed"], "targetHours": "7-8.5 hours, experiment to find your optimal duration", "chronotypeAdvice": "Determine if you're naturally an early bird (lion) or night owl (wolf). Work with your biology rather than against it. Most people fall somewhere in the middle (bear chronotype)."}, "nutritionPrinciples": {"keyFoods": ["Wild-caught fatty fish (salmon, sardines, mackerel)", "Pasture-raised eggs", "Grass-fed beef and organ meats", "Cruciferous vegetables (broccoli, cauliflower, cabbage)", "Leafy greens", "Ber