cy": "Twice weekly", "cycleLength": "8 weeks"}], "safetyGuidelines": ["Do not exceed 200mg/week of testosterone.", "Monitor blood markers regularly to adjust protocol safely.", "Ensure adequate hydration and monitor liver enzymes if any oral medications or supplements are added."], "bloodworkMonitoring": [{"marker": "Testosterone", "frequency": "Every 3-6 months", "targetRange": "500-900 ng/dL"}, {"marker": "Estradiol", "frequency": "Every 3-6 months", "targetRange": "20-30 pg/mL"}, {"marker": "Hemoglobin and Hematocrit", "frequency": "Every 6 months", "targetRange": "14-18 g/dL for Hemoglobin, 40-54% for Hematocrit"}, {"marker": "Liver Function (ALT/AST)", "frequency": "Every 3 months", "targetRange": "7-56 U/L"}, {"marker": "Lipid Profile", "frequency": "Every 6 months", "targetRange": "HDL > 40 mg/dL, LDL < 100 mg/dL"}]}
